INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-acfc4025-moex-00441', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '西方民主理論的主張隨不同時期而有所不同，下列何者最可能是菁英民主理論所支持的主張？', '["政府決策過程應重視不同群體參與之機會", "民主參與是實現公民責任與實踐道德的過程", "社會各界有不同利益與意見，各界菁英皆會影響政府施政", "大眾參政有其困難，因此應強調代議士實踐民主的機制"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 21, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00442', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '社會上對於我國中央政府體制應該如何調整有不同看法，而內閣制是其中一個選項。若我國修憲將中央 政府體制改為典型「內閣制」後，下列敘述何者正確？', '["總統覆議權將擴張故易形成政治僵局", "閣揆將由國會多數黨或執政聯盟產生", "行政與立法的互動關係將會走向分立", "總統與閣揆分享權力的趨勢更為明顯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00443', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '俄烏戰爭開打後，英國禁止俄羅斯船隻進港，歐盟限制俄羅斯進入歐盟資本市場，美國則禁止俄羅斯進 行涉及美元的金融交易，部分精品名牌將暫時關閉俄羅斯境內的店面。從國際政治觀點來看，下列敘述 何者最能反映上述之情境？', '["國際社會的主體就是以國家為單位在運作", "國際社會的互動形式存在衝突也存在競爭", "很常使用經濟制裁方式來維護地區性和平", "落實人道主義的譴責行動是各國應盡責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00444', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '由於網路交友盛行，某甲盜用某乙的照片當作自己交友網站上的大頭貼，被乙的友人發現後轉知乙。乙 獲知自己的照片被盜用後，決定捍衛自己的肖像權。下列何者不能作為乙解決與甲糾紛的途徑？', '["乙透過臉書聯絡甲於媽祖廟和解，兩人私下協議並作成和解契約", "乙對甲提告，雙方可在第一審訴訟進行中，合意向法院聲請調解", "乙與甲可在訴訟外達成民事和解", "若甲不履行訴訟外和解契約的內容，乙可逕行向法院聲請強制執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00445', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '汽車駕駛人違規停車，依道路交通管理處罰條例遭裁罰新臺幣1,000元，該裁罰之法律上性質應屬下 列何者？', '["行政罰", "特別刑罰", "促其履行義務之怠金", "特別公課"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00446', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '憲法第53條明定行政院為國家最高行政機關，使所有國家之行政事務，均納入以行政院為金字塔頂端之 層級式行政體制掌理，經由層級節制，最終並均歸行政院之指揮監督。該條規定之主要目的，在於維護 下列何種原則？', '["法律保留原則", "行政一體原則", "法律優越原則", "代議民主原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00447', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '關於限制人身自由的各類處分，下列何者依現行法制無須由法院為之？', '["社會秩序維護法所規定之拘留", "刑事訴訟法所規定之羈押", "行政執行法所規定之管收", "傳染病防治法所規定之強制隔離"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00448', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '依國家賠償法規定，受害人民請求損害賠償時，應先行下列何種程序？', '["應先向賠償義務機關之上級機關提出賠償申請", "應先向行政法院提起訴訟確認賠償責任歸屬", "應先以書面向賠償義務機關請求並與其協議", "應先向監察院舉報立案並提供相關具體事證"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00449', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '人民因行政機關對其依法申請之案件予以駁回，而認為其權利受到違法損害者，經訴願程序未獲救濟， 此時依行政訴訟法之規定，應提起下列何種類型之訴訟，以請求作成特定內容之行政處分？', '["課予義務訴訟", "撤銷訴訟", "一般給付訴訟", "確認行政處分違法訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00450', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '參加國家考試的阿明對於考試信心滿滿，收到考試成績單後，居然落榜！他決定提起救濟。關於阿明行 政救濟的程序，下列何者正確？', '["阿明對於成績有疑義要向辦理國家考試的考試院提申訴", "若不服訴願結果，可向地方法院行政訴訟庭提起第一審訴訟", "若阿明不服第一審訴訟結果，還可以上訴到最高行政法院", "若最高行政法院判決敗訴，阿明可以透過非常上訴尋求救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL)
